		r.Post("/warehouses/{id}/locations", stock.CriarLocalizacao)
		r.Put("/warehouses/{id}/locations/{loc_id}", stock.ActualizarLocalizacao)
		r.Delete("/warehouses/{id}/locations/{loc_id}", stock.RemoverLocalizacaoSeguro)
		r.Get("/items", stock.ListarStockItems)
