		r.Post("/items", stock.InicializarStockItemSeguro)
		r.Put("/items/{id}/minimos", stock.DefinirMinimoMaximoSeguro)
		r.Get("/movements", stock.ListarMovimentosCompleto)
		r.Post("/movements", stock.RegistarMovimentoSeguro)
		r.Get("/movements/{id}", stock.ObterMovimento)
		r.Get("/adjustments", stock.ListarAjustesCompleto)
		r.Post("/adjustments", stock.CriarAjusteSeguro)
		r.Get("/adjustments/{id}", stock.ObterAjuste)
		r.Get("/transfers", stock.ListarTransferenciasCompleto)
		r.Post("/transfers", stock.CriarTransferenciaCompleta)
		r.Get("/transfers/{id}", stock.ObterTransferencia)
		r.Post("/transfers/{id}/confirmar", stock.ConfirmarTransferencia)
		r.Post("/transfers/{id}/receber", stock.ReceberTransferencia)
		r.Post("/transfers/{id}/cancelar", stock.CancelarTransferencia)
		r.Get("/reservations", stock.ListarReservas)
		r.Post("/reservations", stock.CriarReserva)
		r.Get("/reservations/{id}", stock.ObterReserva)
		r.Post("/reservations/{id}/liberar", stock.LiberarReserva)
		r.Post("/reservations/{id}/consumir", stock.ConsumirReserva)
		r.Get("/batches/a-expirar", stock.LotesAExpirar)
		r.Get("/batches", stock.ListarLotes)
		r.Post("/batches", stock.CriarLote)
		r.Get("/batches/{id}", stock.ObterLote)
		r.Put("/batches/{id}", stock.ActualizarLote)
		r.Get("/serials", stock.ListarSeriais)
		r.Post("/serials", stock.CriarSerial)
		r.Get("/serials/{serial}", stock.ObterSerial)
		r.Put("/serials/{id}/status", stock.ActualizarStatusSerial)
		r.Get("/counts", stock.ListarContagens)
		r.Post("/counts", stock.CriarContagem)
		r.Get("/counts/{id}", stock.ObterContagem)
