			r.Post("/{id}/componentes-salariais", rh.AdicionarComponenteFuncionario)
			r.Delete("/{id}/componentes-salariais/{componenteId}", rh.RemoverComponenteFuncionario)
			r.Get("/{id}/beneficios", rh.ListarBeneficiosFuncionario)
			r.Post("/{id}/beneficios", rh.AdicionarBeneficioFuncionario)
			r.Delete("/{id}/beneficios/{beneficioId}", rh.RemoverBeneficioFuncionario)
			r.Get("/{id}/formacoes", rh.ListarFormacoesFuncionario)
			r.Post("/{id}/formacoes", rh.AdicionarFormacaoFuncionario)
			r.Put("/{id}/formacoes/{registoId}", rh.ActualizarFormacaoFuncionario)
			r.Delete("/{id}/formacoes/{registoId}", rh.RemoverFormacaoFuncionario)
			r.Get("/{id}/presencas", rh.ListarPresencas)
			r.Post("/{id}/presencas", rh.CriarPresenca)
