			r.Get("/{id}/saldos-ausencia", rh.ListarSaldosAusenciaFuncionario)
			r.Post("/{id}/saldos-ausencia", rh.DefinirSaldoAusencia)
			r.Get("/{id}/processos-disciplinares", rh.ListarProcessosDisciplinaresFuncionario)
			r.Post("/{id}/processos-disciplinares", rh.CriarProcessoDisciplinarFuncionario)
			r.Put("/{id}/processos-disciplinares/{registoId}", rh.ActualizarProcessoDisciplinarFuncionario)
			r.Delete("/{id}/processos-disciplinares/{registoId}", rh.RemoverProcessoDisciplinarFuncionario)
